typedef float fp;

#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x) + (A.y)*(B.y) + (A.z)*(B.z))

typedef struct
{
	fp x, y, z;
} THREE_VECTOR;

typedef struct
{
	fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str
{
	int x, y, z;
	int number;
	long offset;
} nei_str;

typedef struct box_str
{
	int x, y, z;
	int number;
	long offset;
	int nn;
	nei_str nei[26];
} box_str;

typedef struct par_str
{
	fp alpha;
} par_str;

typedef struct dim_str
{
	int cur_arg;
	int arch_arg;
	int cores_arg;
	int boxes1d_arg;
	long number_boxes;
	long box_mem;
	long space_elem;
	long space_mem;
	long space_mem2;
} dim_str;

__kernel void kernel_gpu_opencl(	par_str par,
									dim_str dim,
									__global const box_str* box,
									__global const FOUR_VECTOR* rv,
									__global const fp* qv,
									__global FOUR_VECTOR* fv)
{
	const long l = (long)get_group_id(0);
	const int i = (int)get_local_id(0);

	if (l >= dim.number_boxes || i >= NUMBER_PAR_PER_BOX) {
		return;
	}

	const fp alpha = par.alpha;
	const fp a2 = 2.0f * alpha * alpha;

	const long first_i = box[l].offset;
	const FOUR_VECTOR rA = rv[first_i + i];
	FOUR_VECTOR fA = fv[first_i + i];

	for (int k = 0; k < (1 + box[l].nn); k++) {

		int pointer;
		if (k == 0) {
			pointer = (int)l;
		}
		else {
			pointer = box[l].nei[k - 1].number;
		}

		const long first_j = box[pointer].offset;

		for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {

			const FOUR_VECTOR rB = rv[first_j + j];
			const fp qB = qv[first_j + j];

			const fp r2 = rA.v + rB.v - DOT(rA, rB);
			const fp u2 = a2 * r2;
			const fp vij = exp(-u2);
			const fp fs = 2.0f * vij;

			THREE_VECTOR d;
			d.x = rA.x - rB.x;
			d.y = rA.y - rB.y;
			d.z = rA.z - rB.z;

			const fp fxij = fs * d.x;
			const fp fyij = fs * d.y;
			const fp fzij = fs * d.z;

			fA.v += qB * vij;
			fA.x += qB * fxij;
			fA.y += qB * fyij;
			fA.z += qB * fzij;
		}
	}

	fv[first_i + i] = fA;
}
